  ('pukao-6f0ba476-moex-00009', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於2025年1月5日收到一張帳單，內容為2024年12月的廣告費用$12,000，預計將於1 月10日付款。請問甲公司應於那一年度認列此筆費用？', '["2024年", "2025年", "2024或2025年皆可", "不需認列，直到付款為止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00010', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', 'A公司採永續盤存制。某日賒銷並寄出商品給B公司，售價為$15,000，成本為$8,000，交貨條件 為目的地交貨。假設貨物隔日才送達，請問下列那一個分錄正確反映賒銷並寄出商品當日與存貨 相關的會計處理？', '["借：銷貨成本8,000；貸：存貨8,000", "借：進貨8,000；貸：銷貨成本8,000", "借：銷貨成本8,000；貸：進貨8,000", "無需作任何與存貨有關的分錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00011', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X5年5月1日購入一台機器，定價為$250,000，議定以九五折成交，付款條件為1/10,n/30， 且公司於折扣期限內全額付款。此外，公司另支出安裝費用$5,000，機器試車費用$3,000，機器於 安裝時發生損壞，修理費用$2,200。請問該機器的入帳成本為多少？', '["$235,125", "$240,125", "$243,125", "$245,325"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00012', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年年初以$10,000投資取得乙公司40%的普通股，並對乙公司具有重大影響，因此採 用權益法進行會計處理。X1年度乙公司淨利為$1,000，並宣告發放現金股利$500。該投資無需攤 銷差額。請問：甲公司於X1年度應認列之投資收益金額、股利收入金額與X1年底投資帳面金額 分別為何？', '["投資收益為$400，股利收入為$0，期末投資帳面金額為 $10,200", "投資收益為$400，股利收入為$200，期末投資帳面金額為$10,600", "投資收益為$200，股利收入為$200，期末投資帳面金額為$10,200", "投資收益為$200，股利收入為$0，期末投資帳面金額為$10,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00013', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司本年度的銷貨收入與去年相當，但期末應收帳款與存貨均大幅增加。根據財務報表分析基 本原則，下列那一項最合理地解釋這一情況？', '["公司收現能力提升，且銷貨暢旺造成庫存不足", "公司收現速度變慢，且存貨周轉速度下降", "公司提高銷貨價格，導致帳款與庫存增加", "公司應收帳款與存貨同時增加，代表利潤穩定且現金流改善"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00014', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司X1年度淨利為$25,000，另提供下列資訊： 折舊費用：$5,000 應收帳款增加：$3,000 存貨減少：$2,000 購置設備支出：$6,000 發行普通股收現：$10,000 發放現金股利：$4,000 請問，下列那一組金額正確反映甲公司 X1 年度的營業活動、投資活動、籌資活動之現金流量， 以及現金及約當現金淨增減數？其中以括號()表示現金流出。', '["營業活動：$29,000；投資活動：($6,000)；籌資活動：$6,000；現金及約當現金淨增加數：$29,000", "營業活動：$29,000；投資活動：($6,000)；籌資活動：$6,000；現金及約當現金淨增加數：$25,000", "營業活動：$27,000；投資活動：($6,000)；籌資活動：$10,000；現金及約當現金淨增加數：$31,000", "營業活動：$29,000；投資活動：($6,000)；籌資活動：$10,000；現金及約當現金淨增加數：$33,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00015', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司截至X1年12月31日的資產為$100,000，負債為$30,000。該公司已發行累積特別股2,000 股（面額每股$10，年股利率10%），並於X1年底累積未支付X0年與X1年兩年度之股利。另有 普通股5,000股（面額每股$10）全年流通在外。X1年度未宣告任何股利，X1年淨利為$8,000。 請問：X1年底普通股每股淨值為何？', '["$9.20", "$13.20", "$14.00", "$15.00 41430"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00016', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '承上題，請問：X1年底每股盈餘？', '["$1.00", "$1.20", "$1.4", "$1.6"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00017', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日發行面額$100,000、票面利率6%、5年期公司債，發行價格為$92,000。 每年1月1日付息，共五期。公司採用有效利息法攤銷折價，市場有效利率為8%。請問：截至 X1年12月31日止，下列有關該公司債之財務報導金額何者正確？', '["損益表利息費用為$6,000；資產負債表應付公司債帳面金額為$92,000", "損益表利息費用為$7,360；資產負債表應付公司債帳面金額為$92,000", "損益表利息費用為$7,360；資產負債表應付公司債帳面金額為$93,360", "損益表利息費用為$6,000；資產負債表應付公司債帳面金額為$93,360"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00018', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '下列何者不屬於「負債準備」之適當範疇？', '["公司長期提供產品保固服務，雖無法律強制規定，但因一貫對外承諾與實務慣例，構成推定義務", "公司已正式對外公告重組計畫，並於報導日前通知受影響員工，預計產生解僱費用", "公司預計在未來年度進行廠房設備升級，以因應新的產品線，尚未簽約或對外承諾", "公司過去於顧客退貨時多會接受退貨，雖契約無退貨條款，市場亦普遍預期可退"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
